import{_ as o,o as a,c as d,a2 as t}from"./chunks/framework.DvFsUg-r.js";const m=JSON.parse('{"title":"플랫폼 관리 프론트엔드 — Data Model (Phase 1)","description":"","frontmatter":{"title":"플랫폼 관리 프론트엔드 — Data Model (Phase 1)","feature_id":"006","created":"2026-05-31 16:40 (KST)","date":"2026-05-31T00:00:00.000Z"},"headers":[],"relativePath":"specs/006-platform-admin-frontend/data-model.md","filePath":"specs/006-platform-admin-frontend/data-model.md","lastUpdated":null}'),c={name:"specs/006-platform-admin-frontend/data-model.md"};function i(l,e,r,s,n,u){return a(),d("div",null,[...e[0]||(e[0]=[t('<h1 id="data-model-플랫폼-관리-프론트엔드-클라이언트-상태" tabindex="-1">Data Model: 플랫폼 관리 프론트엔드 (클라이언트 상태) <a class="header-anchor" href="#data-model-플랫폼-관리-프론트엔드-클라이언트-상태" aria-label="Permalink to &quot;Data Model: 플랫폼 관리 프론트엔드 (클라이언트 상태)&quot;">​</a></h1><p>프론트는 신규 영속 엔터티가 없다. 여기서 &quot;모델&quot;은 <strong>클라이언트 상태(Pinia 스토어)</strong> 와 백엔드 응답을 받는 <strong>뷰 타입</strong>(005 OpenAPI 에서 생성)이다. 서버 스키마는 004 data-model 이 출처.</p><h2 id="pinia-스토어" tabindex="-1">Pinia 스토어 <a class="header-anchor" href="#pinia-스토어" aria-label="Permalink to &quot;Pinia 스토어&quot;">​</a></h2><h3 id="authstore" tabindex="-1">authStore <a class="header-anchor" href="#authstore" aria-label="Permalink to &quot;authStore&quot;">​</a></h3><ul><li>상태: <code>accessToken: string | null</code>(메모리), <code>refreshToken: string | null</code>, <code>user: { username, name, roles: string[] } | null</code>, <code>status: &#39;anon&#39;|&#39;authed&#39;</code>.</li><li>액션: <code>login(username, password)</code>, <code>logout()</code>, <code>refresh()</code>, <code>loadMe()</code>.</li><li>게터: <code>isAuthenticated</code>, <code>isAdmin</code>(roles 에 <code>ADMIN</code>), <code>hasRole(code)</code>.</li><li>전이: <code>anon ──login──&gt; authed</code>, <code>authed ──401&amp;refresh실패/logout──&gt; anon</code>.</li></ul><h3 id="menustore" tabindex="-1">menuStore <a class="header-anchor" href="#menustore" aria-label="Permalink to &quot;menuStore&quot;">​</a></h3><ul><li>상태: <code>tree: MenuNode[]</code>(<code>/menus/my</code> 결과), <code>favorites: MenuRow[]</code>, <code>loaded: boolean</code>.</li><li>액션: <code>loadMyMenus()</code>, <code>loadFavorites()</code>, <code>addFavorite(id)</code>, <code>removeFavorite(id)</code>.</li><li>용도: 좌측 동적 네비 + 라우트 권한 가드(접근 가능 경로 집합 유도).</li></ul><h3 id="uistore-공통-ux" tabindex="-1">uiStore (공통 UX) <a class="header-anchor" href="#uistore-공통-ux" aria-label="Permalink to &quot;uiStore (공통 UX)&quot;">​</a></h3><ul><li>상태: <code>loadingCount: number</code>, <code>toasts: { type, message }[]</code>.</li><li>액션: <code>pushToast(type, message)</code>, <code>withLoading(promise)</code>. API 인터셉터가 갱신.</li></ul><h2 id="뷰-타입-005-openapi-생성-—-types-api-d-ts" tabindex="-1">뷰 타입 (005 OpenAPI 생성 — <code>types/api.d.ts</code>) <a class="header-anchor" href="#뷰-타입-005-openapi-생성-—-types-api-d-ts" aria-label="Permalink to &quot;뷰 타입 (005 OpenAPI 생성 — `types/api.d.ts`)&quot;">​</a></h2><p>백엔드 DTO 를 그대로 타입으로 받는다(예시, 생성 산출물 기준):</p><ul><li>인증: <code>LoginRequest</code>, <code>TokenResponse{accessToken, refreshToken}</code>, <code>MeResponse{username,name,roles,menus}</code>.</li><li>공통: <code>ApiResponse&lt;T&gt;{success, code, message, data}</code>, <code>PageResponse&lt;T&gt;{content,totalElements,totalPages,size,number}</code>.</li><li>RBAC(MVP): <code>UserDto</code>, <code>RoleDto</code>, <code>DeptDto</code>, <code>MenuNode</code>/<code>MenuRow</code>, <code>RoleMenuPermission</code>.</li><li>후속: 코드·메시지·설정·감사 7종·결재·권한신청·메일·파일 DTO(생성 타입 그대로).</li></ul><h2 id="datagrid-모델-공통-컴포넌트-계약" tabindex="-1">DataGrid 모델 (공통 컴포넌트 계약) <a class="header-anchor" href="#datagrid-모델-공통-컴포넌트-계약" aria-label="Permalink to &quot;DataGrid 모델 (공통 컴포넌트 계약)&quot;">​</a></h2><ul><li>입력: <code>columns: { field, header, width?, type? }[]</code>, <code>rows: T[]</code>, <code>total: number</code>, <code>page</code>, <code>size</code>, <code>keyword</code>, <code>loading</code>.</li><li>이벤트: <code>@update:query({page,size,keyword,filters})</code> → 화면이 API 재호출.</li><li>구현: VuGrid 래퍼(가상 스크롤). 소규모는 Vuetify <code>v-data-table</code> 대체 가능(R4).</li></ul><h2 id="검증-규칙-클라이언트" tabindex="-1">검증 규칙(클라이언트) <a class="header-anchor" href="#검증-규칙-클라이언트" aria-label="Permalink to &quot;검증 규칙(클라이언트)&quot;">​</a></h2><ul><li>폼 제출 전 필수/형식 검증(Vuetify rules). 서버 검증 실패(400/409/404/403)는 토스트로 표시.</li><li>권한: 라우트 진입 가드가 <code>menuStore</code>/<code>authStore</code> 로 접근 차단(서버 통제와 이중 안전).</li><li>토큰: Access 만료 시 인터셉터가 refresh; 실패 시 상태 <code>anon</code> 전이 + 로그인 이동.</li></ul>',16)])])}const p=o(c,[["render",i]]);export{m as __pageData,p as default};
